import { createPinia } from 'pinia';
import piniaPluginPersistedstate from 'pinia-plugin-persistedstate';
import axios from 'axios';

import App from './App.vue';
import { VueDraggableGrid } from './plugins/vue-grid-layout';
import router from './router';

import { PrimeVue, FtTheme, ToastService } from './plugins/primevue';

/**
 * LumiTrade Auto-Login
 *
 * If no bot is configured in localStorage, automatically:
 * 1. Fetch credentials from LumiGate server (/lumitrade/auto-auth)
 * 2. Call Freqtrade login API to obtain tokens
 * 3. Store bot config + tokens in localStorage
 *
 * This runs BEFORE Vue mounts so the router guard sees a valid bot.
 */
async function autoLogin(): Promise<void> {
  const AUTH_KEY = 'ftAuthLoginInfo';
  const SEL_KEY = 'ftSelectedBot';
  const BOT_ID = 'ftbot.0';

  // Always re-login to ensure fresh tokens (old tokens may be expired)

  try {
    // Step 1: Fetch credentials from LumiGate auto-auth endpoint
    const { data: creds } = await axios.get('/lumitrade/auto-auth', { timeout: 3000 });
    if (!creds || !creds.username || !creds.password) {
      console.log('[LumiTrade] auto-auth endpoint did not return credentials, skipping auto-login');
      return;
    }

    // Use browser origin + /lumitrade as API URL (nginx proxies to freqtrade)
    const apiUrl = window.location.origin + '/lumitrade';
    const botName = creds.botName || 'LumiTrade';

    // Step 2: Call Freqtrade token/login API (relative path via nginx proxy)
    const { data: tokenResp } = await axios.post(
      `/lumitrade/api/v1/token/login`,
      {},
      {
        auth: { username: creds.username, password: creds.password },
        withCredentials: true,
        timeout: 5000,
      },
    );

    if (!tokenResp.access_token || !tokenResp.refresh_token) {
      console.warn('[LumiTrade] auto-login: token response missing tokens');
      return;
    }

    // Step 3: Also login to backtest instance
    let btToken = '', btRefresh = '';
    try {
      const { data: btResp } = await axios.post(
        `/lumitrade/bt/api/v1/token/login`,
        {},
        { auth: { username: creds.username, password: creds.password }, timeout: 5000 },
      );
      btToken = btResp.access_token || '';
      btRefresh = btResp.refresh_token || '';
    } catch { /* backtest instance may not be running */ }

    // Step 4: Store both bots in localStorage
    const btApiUrl = window.location.origin + '/lumitrade/bt';
    const authStorage: Record<string, any> = {
      [BOT_ID]: {
        botName,
        apiUrl,
        username: creds.username,
        refreshToken: tokenResp.refresh_token,
        accessToken: tokenResp.access_token,
        autoRefresh: true,
        sortId: 0,
      },
    };
    if (btToken) {
      authStorage['ftbot.1'] = {
        botName: 'Backtest',
        apiUrl: btApiUrl,
        username: creds.username,
        refreshToken: btRefresh,
        accessToken: btToken,
        autoRefresh: true,
        sortId: 1,
      };
    }
    localStorage.setItem(AUTH_KEY, JSON.stringify(authStorage));
    localStorage.setItem(SEL_KEY, BOT_ID);

    console.log('[LumiTrade] auto-login successful');
  } catch (err) {
    console.warn('[LumiTrade] auto-login failed, user will see login form:', err);
    // Fall through — user will see the normal login form
  }
}

async function bootstrap() {
  // Attempt auto-login before Vue mounts
  await autoLogin();

  const myApp = createApp(App);

  const pinia = createPinia();
  pinia.use(piniaPluginPersistedstate);
  myApp.use(pinia);

  myApp.use(PrimeVue, {
    theme: {
      preset: FtTheme,
      options: {
        darkModeSelector: '.ft-dark-theme',
        cssLayer: {
          name: 'primevue',
          order: 'theme, base, primevue',
        },
      },
    },
  });
  myApp.use(ToastService);

  myApp.use(router);
  myApp.use(VueDraggableGrid);

  myApp.mount('#app');
}

bootstrap();
